const input = $input.first().json || {};
const body = input.body && typeof input.body === "object" ? input.body : input;
const barberiaId = Number(body.barberia_id || body.id_barberia || 0);
return [{
  json: {
    email: String(body.email || "").trim().toLowerCase(),
    password: String(body.password || ""),
    slug: String(body.slug || body.barberia_slug || "").trim(),
    barberia_id: Number.isFinite(barberiaId) && barberiaId > 0 ? barberiaId : null
  }
}];

const pgItems = $items('Code - format', 0, 0) || [];
const base = pgItems[0]?.json || {};
const jwtOut = $input.first().json || {};
const token = jwtOut.token ?? null;

const clearCookie = 'ba_session=; Path=/; Max-Age=0; HttpOnly; Secure; SameSite=Lax';

if (!base.ok || !base.user?.id) {
  return [{
    json: {
      ...base,
      set_cookie: clearCookie,
    }
  }];
}

if (!token) {
  return [{
    json: {
      ...base,
      ok: false,
      message: 'Token de session no generado',
      set_cookie: clearCookie,
    }
  }];
}

const maxAge = 604800;
const cookie = 'ba_session=' + token + '; Path=/; Max-Age=' + maxAge + '; HttpOnly; Secure; SameSite=Lax';

return [{
  json: {
    ...base,
    set_cookie: cookie,
  }
}];

